type Theme = (typeof THEMES)[number]

function Corner({ color, deg }: { color: string; deg: number }) {
  return (
    <svg viewBox="0 0 14 14" width="13" height="13" style={{ transform: `rotate(${deg}deg)` }} aria-hidden="true">
      <path d="M0,0 L10,0 L10,1.8 L1.8,1.8 L1.8,10 L0,10 Z" fill={color} opacity="0.5" />
    </svg>
  )
}

function Divider({ color }: { color: string }) {
  return (
    <svg viewBox="0 0 56 10" width="52" height="9" aria-hidden="true">
      <line x1="0"  y1="4.5" x2="19" y2="4.5" stroke={color} strokeWidth="0.5" opacity="0.5" />
      <rect x="23" y="1.5"   width="6" height="6" transform="rotate(45 26 4.5)" fill={color} opacity="0.5" />
      <line x1="33" y1="4.5" x2="56" y2="4.5" stroke={color} strokeWidth="0.5" opacity="0.5" />
    </svg>
  )
}

function ThemeCard({ theme, index }: { theme: Theme; index: number }) {
  return (
    <motion.a
      href={theme.href}
      target="_blank"
      rel="noopener noreferrer"
      className="relative flex-none snap-center group focus:outline-none"
      style={{ width: 'clamp(148px, 52vw, 216px)' }}
      initial={{ opacity: 0, y: 28 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: '-40px' }}
      transition={{ duration: 0.8, ease: [0.22, 1, 0.36, 1], delay: index * 0.08 }}
      aria-label={`Preview ${theme.label} theme`}
    >
      {/* Card face */}
      <div
        className="relative overflow-hidden"
        style={{
          aspectRatio: '9 / 16',
          borderRadius: 6,
          boxShadow: '0 12px 48px rgba(0,0,0,0.16), 0 2px 8px rgba(0,0,0,0.08)',
        }}
      >
        {/* Wedding photo */}
        <div
          style={{
            position: 'absolute',
            inset: 0,
            backgroundImage: `url(${theme.photo})`,
            backgroundSize: 'cover',
            backgroundPosition: 'center',
            zIndex: 0,
          }}
        />
        {/* Theme color overlay */}
        <div
          style={{
            position: 'absolute',
            inset: 0,
            background: theme.bg,
            opacity: 0.65,
            zIndex: 1,
          }}
        />

        {/* Content */}
        <div className="absolute inset-0" style={{ zIndex: 2 }}>
          {/* Corners */}
          <div style={{ position: 'absolute', top: 12, left: 12 }}>
            <Corner color={theme.accent} deg={0} />
          </div>
          <div style={{ position: 'absolute', top: 12, right: 12 }}>
            <Corner color={theme.accent} deg={90} />
          </div>
          <div style={{ position: 'absolute', bottom: 12, left: 12 }}>
            <Corner color={theme.accent} deg={270} />
          </div>
          <div style={{ position: 'absolute', bottom: 12, right: 12 }}>
            <Corner color={theme.accent} deg={180} />
          </div>

          {/* Centered content */}
          <div className="absolute inset-0 flex flex-col items-center justify-center gap-3 px-5 text-center">
            <span style={{ fontFamily: 'var(--font-inter)', fontSize: 7, letterSpacing: '0.28em', textTransform: 'uppercase', color: theme.fg, opacity: 0.38 }}>
              You are invited
            </span>
            <Divider color={theme.accent} />
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 1 }}>
              <span style={{ fontFamily: 'var(--font-cormorant)', fontSize: 'clamp(1.1rem, 3.5vw, 1.6rem)', fontWeight: 300, color: theme.fg, lineHeight: 1.15 }}>
                {theme.name1}
              </span>
              <span style={{ fontFamily: 'var(--font-cormorant)', fontSize: 'clamp(0.7rem, 2vw, 1rem)', fontStyle: 'italic', color: theme.accent, lineHeight: 1.4 }}>
                &amp;
              </span>
              <span style={{ fontFamily: 'var(--font-cormorant)', fontSize: 'clamp(1.1rem, 3.5vw, 1.6rem)', fontWeight: 300, color: theme.fg, lineHeight: 1.15 }}>
                {theme.name2}
              </span>
            </div>
            <Divider color={theme.accent} />
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4 }}>
              <span style={{ fontFamily: 'var(--font-inter)', fontSize: 7, letterSpacing: '0.2em', color: theme.fg, opacity: 0.5 }}>
                {theme.date}
              </span>
              <span style={{ fontFamily: 'var(--font-inter)', fontSize: 6.5, letterSpacing: '0.12em', color: theme.fg, opacity: 0.32 }}>
                {theme.loc}
              </span>
            </div>
          </div>

          {/* Hover overlay */}
          <div
            className="absolute inset-0 hidden md:flex items-center justify-center transition-opacity duration-300 opacity-0 group-hover:opacity-100"
            style={{ background: 'rgba(0,0,0,0.38)' }}
          >
            <span style={{ fontFamily: 'var(--font-inter)', fontSize: 9, letterSpacing: '0.24em', textTransform: 'uppercase', color: '#fff' }}>
              Preview
            </span>
          </div>
        </div>
      </div>

      {/* Label */}
      <div className="mt-4 flex items-center justify-between px-0.5">
        <span
          className="font-inter tracking-[0.18em] uppercase group-hover:opacity-50 transition-opacity duration-300"
          style={{ fontSize: 9, color: 'rgba(26,26,26,0.38)' }}
        >
          {theme.label}
        </span>
        <span style={{ fontFamily: 'var(--font-inter)', fontSize: 10, color: 'rgba(26,26,26,0.18)' }}>→</span>
      </div>
    </motion.a>
  )
}

export function GallerySection() {
  const reduced  = useReducedMotion()
  const trackRef = useRef<HTMLDivElement>(null)

  return (
    <section id="themes" className="overflow-hidden" style={{ background: '#F3EDE5', paddingTop: '6rem', paddingBottom: '3rem' }} aria-label="Design themes">

      {/* Header */}
      <div className="px-6 md:px-14 mb-12">
        <motion.div
          initial={{ opacity: 0, y: 16 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.9, ease: [0.22, 1, 0.36, 1] }}
        >
          <span className="font-inter tracking-[0.32em] uppercase" style={{ fontSize: 9, color: 'rgba(26,26,26,0.28)' }}>
            Themes
          </span>
          <h2
            className="font-cormorant font-light text-[#1A1A1A] mt-2 leading-none"
            style={{ fontSize: 'clamp(2.2rem, 7vw, 4rem)', letterSpacing: '-0.015em' }}
          >
            Find your aesthetic.
          </h2>
        </motion.div>
      </div>

      {/* Scrollable row */}
      <motion.div
        ref={trackRef}
        className="flex overflow-x-auto snap-x snap-mandatory gap-4 md:gap-6 px-6 md:px-14 pb-8 no-scrollbar touch-pan-x"
        drag={reduced ? false : 'x'}
        dragConstraints={trackRef}
        style={{ WebkitOverflowScrolling: 'touch', cursor: 'grab' }}
        whileTap={{ cursor: 'grabbing' }}
      >
        {THEMES.map((theme, i) => (
          <ThemeCard key={theme.id} theme={theme} index={i} />
        ))}
      </motion.div>

      <p
        className="md:hidden font-inter tracking-[0.26em] uppercase text-center mt-1"
        style={{ fontSize: 8, color: 'rgba(26,26,26,0.2)' }}
      >
        Swipe to explore
      </p>
    </section>
  )
}
